// // This module compares two 2-bit inputs, A and B, and outputs a signed integer Z indicating the result of the comparison. If A is greater than B, Z should be -1; if A is less than B, Z should be 1; otherwise, Z should be 0.
module top_module(
    input [1:0] A,
    input [1:0] B,
    output reg Z
);always @ (*) begin
        if(A[1] > B[1]) begin
            Z = 1;
        end else if(A[1] < B[1]) begin
            Z = -1;
        end else if(A[0] > B[0]) begin
            Z = 1;
        end else if(A[0] < B[0]) begin
            Z = -1;
        end else begin
            Z = 0;
        end
    end

endmodule
